import UIKit
import CryptoKit

class Wallet {
    var privateKey: Curve25519.Signing.PrivateKey?
    var publicKey: Curve25519.Signing.PublicKey?

    init() {
        generateKeyPair()
    }

    private func generateKeyPair() {
        privateKey = Curve25519.Signing.PrivateKey()
        publicKey = privateKey?.publicKey
    }

    func signTransaction(data: Data) -> Data? {
        guard let privateKey = privateKey else { return nil }
        let signature = try? privateKey.signature(for: data)
        return signature
    }

    func getPublicKey() -> String? {
        return publicKey?.rawRepresentation.base64EncodedString()
    }

    func getPrivateKey() -> String? {
        return privateKey?.rawRepresentation.base64EncodedString()
    }
}

class BlockchainService {
    let baseURL = "https://api.blockchain.com/v3/exchange"

    func sendTransaction(transactionData: Data, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/send") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = ["transaction": transactionData.base64EncodedString()]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body, options: [])

        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            guard let data = data else { return }
            let responseString = String(data: data, encoding: .utf8) ?? ""
            completion(.success(responseString))
        }
        task.resume()
    }
}

class WalletViewController: UIViewController {
    var wallet = Wallet()
    var blockchainService = BlockchainService()

    override func viewDidLoad() {
        super.viewDidLoad()
        // UI setup and wallet functionalities
    }

    func createTransaction(data: Data) {
        guard let signature = wallet.signTransaction(data: data) else { return }
        blockchainService.sendTransaction(transactionData: signature) { result in
            switch result {
            case .success(let response):
                print("Transaction successful: \(response)")
            case .failure(let error):
                print("Transaction failed: \(error.localizedDescription)")
            }
        }
    }
}